   143→  render: () => (
   144→    <FractalCanvasComplete
   145→      width={window.innerWidth}
   146→      height={window.innerHeight}
   147→      initialZoom={0.5}
   148→      showConstraintDeck={false}
   149→      showTimeScrubber={false}
   150→    />
   151→  ),
   152→};
   153→
   154→export const Interactive: Story = {
   155→  name: 'Interactive Controls',
   156→  render: () => {
   157→    const [zoom, setZoom] = useState(0.5);
   158→    const [showConstraintDeck, setShowConstraintDeck] = useState(true);
   159→    const [showTimeScrubber, setShowTimeScrubber] = useState(true);
   160→
   161→    const getLOD = (z: number) => {
   162→      if (z < 0.3) return 'strategic';
   163→      if (z < 1.0) return 'tactical';
   164→      if (z < 3.0) return 'operational';
   165→      return 'execution';
   166→    };
   167→
   168→    const getIntent = (lod: string) => {
   169→      switch (lod) {
   170→        case 'strategic': return Intent.PRIMARY;
   171→        case 'tactical': return Intent.WARNING;
   172→        case 'operational': return Intent.SUCCESS;
   173→        case 'execution': return Intent.DANGER;
   174→        default: return Intent.NONE;
   175→      }
   176→    };
   177→
   178→    return (
   179→      <div style={{ width: '100%', height: '100vh', display: 'flex', flexDirection: 'column' }}>
   180→        {/* Control bar */}
   181→        <Card style={{ borderRadius: 0, padding: 16 }}>
   182→          <div style={{ display: 'flex', alignItems: 'center', gap: 24, flexWrap: 'wrap' }}>
   183→            <div style={{ flex: 1, minWidth: 300 }}>
   184→              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
   185→                <span style={{ fontWeight: 600 }}>Zoom Level</span>
   186→                <Tag intent={getIntent(getLOD(zoom))} large>
   187→                  {getLOD(zoom).toUpperCase()} ({zoom.toFixed(2)}x)
   188→                </Tag>
   189→              </div>
   190→              <Slider
   191→                min={0.1}
   192→                max={5}
   193→                stepSize={0.01}
   194→                value={zoom}
   195→                onChange={setZoom}
   196→                labelStepSize={1}
   197→              />
   198→            </div>
   199→
   200→            <Divider />
   201→
   202→            <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
   203→              <Switch
   204→                checked={showTimeScrubber}
   205→                onChange={(e) => setShowTimeScrubber(e.currentTarget.checked)}
   206→                label="Time Scrubber"
   207→              />
   208→              <Switch
   209→                checked={showConstraintDeck}
   210→                onChange={(e) => setShowConstraintDeck(e.currentTarget.checked)}
   211→                label="Constraint Deck"
   212→              />
   213→            </div>
   214→
   215→            <Divider />
   216→
   217→            <ButtonGroup>
   218→              <Button
   219→                intent={getLOD(zoom) === 'strategic' ? Intent.PRIMARY : Intent.NONE}
   220→                onClick={() => setZoom(0.2)}
   221→              >
   222→                Strategic
   223→              </Button>
   224→              <Button
   225→                intent={getLOD(zoom) === 'tactical' ? Intent.WARNING : Intent.NONE}
   226→                onClick={() => setZoom(0.6)}
   227→              >
   228→                Tactical
   229→              </Button>
   230→              <Button
   231→                intent={getLOD(zoom) === 'operational' ? Intent.SUCCESS : Intent.NONE}
   232→                onClick={() => setZoom(1.8)}
   233→              >
   234→                Operational
   235→              </Button>
   236→              <Button
   237→                intent={getLOD(zoom) === 'execution' ? Intent.DANGER : Intent.NONE}
   238→                onClick={() => setZoom(4.0)}
