   263→export const LODTransitionDemo: Story = {
   264→  name: 'LOD Transition Demo',
   265→  render: () => {
   266→    const [autoPlay, setAutoPlay] = useState(false);
   267→    const [zoom, setZoom] = useState(0.1);
   268→
   269→    React.useEffect(() => {
   270→      if (!autoPlay) return;
   271→
   272→      const interval = setInterval(() => {
   273→        setZoom((z) => {
   274→          const newZoom = z + 0.02;
   275→          if (newZoom > 5) {
   276→            setAutoPlay(false);
   277→            return 0.1;
   278→          }
   279→          return newZoom;
   280→        });
   281→      }, 100);
   282→
   283→      return () => clearInterval(interval);
   284→    }, [autoPlay]);
   285→
   286→    const getLOD = (z: number) => {
   287→      if (z < 0.3) return 'strategic';
   288→      if (z < 1.0) return 'tactical';
   289→      if (z < 3.0) return 'operational';
   290→      return 'execution';
   291→    };
   292→
   293→    const getOpacity = (z: number, level: string) => {
   294→      const TRANSITION = 0.15;
   295→      if (level === 'strategic') {
   296→        if (z <= 0.3 - TRANSITION) return 1;
   297→        if (z >= 0.3) return 0;
   298→        return 1 - (z - (0.3 - TRANSITION)) / TRANSITION;
   299→      }
   300→      if (level === 'tactical') {
   301→        const fadeIn = z < 0.3 + TRANSITION ? (z - 0.3) / TRANSITION : 1;
   302→        const fadeOut = z > 1.0 - TRANSITION ? 1 - (z - (1.0 - TRANSITION)) / TRANSITION : 1;
   303→        return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
   304→      }
   305→      if (level === 'operational') {
   306→        const fadeIn = z < 1.0 + TRANSITION ? (z - 1.0) / TRANSITION : 1;
   307→        const fadeOut = z > 3.0 - TRANSITION ? 1 - (z - (3.0 - TRANSITION)) / TRANSITION : 1;
   308→        return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
   309→      }
   310→      if (level === 'execution') {
   311→        if (z >= 3.0 + TRANSITION) return 1;
   312→        if (z <= 3.0) return 0;
   313→        return (z - 3.0) / TRANSITION;
   314→      }
   315→      return 0;
   316→    };
   317→
   318→    const lodColors = {
   319→      strategic: '#3b82f6',
   320→      tactical: '#f59e0b',
   321→      operational: '#22c55e',
   322→      execution: '#ef4444',
   323→    };
   324→
   325→    return (
   326→      <div style={{ width: '100%', height: '100vh', display: 'flex', flexDirection: 'column' }}>
   327→        {/* Control bar */}
   328→        <Card style={{ borderRadius: 0, padding: 16 }}>
   329→          <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
   330→            <ButtonGroup>
   331→              <Button
   332→                icon={autoPlay ? 'pause' : 'play'}
   333→                intent={autoPlay ? Intent.DANGER : Intent.SUCCESS}
   334→                onClick={() => setAutoPlay(!autoPlay)}
   335→              >
   336→                {autoPlay ? 'Pause' : 'Auto-Play'}
   337→              </Button>
   338→              <Button icon="reset" onClick={() => setZoom(0.1)}>
   339→                Reset
   340→              </Button>
   341→            </ButtonGroup>
   342→
   343→            <div style={{ flex: 1 }}>
   344→              <Slider
   345→                min={0.1}
   346→                max={5}
   347→                stepSize={0.01}
   348→                value={zoom}
   349→                onChange={setZoom}
   350→                labelStepSize={1}
   351→                disabled={autoPlay}
   352→              />
   353→            </div>
   354→
   355→            <div style={{ display: 'flex', gap: 16 }}>
   356→              {(['strategic', 'tactical', 'operational', 'execution'] as const).map((level) => {
   357→                const opacity = getOpacity(zoom, level);
   358→                return (
   359→                  <div key={level} style={{ textAlign: 'center' }}>
   360→                    <div
   361→                      style={{
   362→                        width: 60,
   363→                        height: 8,
   364→                        background: `linear-gradient(to right, ${lodColors[level]} ${opacity * 100}%, #e5e7eb ${opacity * 100}%)`,
   365→                        borderRadius: 4,
   366→                        marginBottom: 4,
   367→                      }}
   368→                    />
   369→                    <div style={{ fontSize: 10, fontWeight: 500 }}>{level}</div>
   370→                    <div style={{ fontSize: 10, color: '#666' }}>{Math.round(opacity * 100)}%</div>
   371→                  </div>
   372→                );
   373→              })}
   374→            </div>
   375→          </div>
   376→        </Card>
   377→
   378→        {/* Canvas */}
   379→        <div style={{ flex: 1 }}>
   380→          <FractalCanvasComplete
   381→            width={window.innerWidth}
   382→            height={window.innerHeight - 80}
   383→            initialZoom={zoom}
   384→            showConstraintDeck={true}
   385→            showTimeScrubber={true}
   386→            enableKeyboard={false}
   387→            key={Math.floor(zoom * 10)}
   388→          />
   389→        </div>
   390→      </div>
   391→    );
   392→  },
   393→};
   394→
   395→export const Presentation: Story = {
   396→  name: 'Presentation Mode',
   397→  parameters: {
   398→    backgrounds: { default: 'dark' },
   399→  },
   400→  render: () => {
   401→    const [currentSlide, setCurrentSlide] = useState(0);
   402→
   403→    const slides = [
   404→      { zoom: 0.15, title: 'Strategic View', subtitle: '12-year capacity heatmap' },
   405→      { zoom: 0.3, title: 'Strategic → Tactical', subtitle: 'Crossfade transition' },
   406→      { zoom: 0.6, title: 'Tactical View', subtitle: 'Monthly workload bars' },
   407→      { zoom: 1.0, title: 'Tactical → Operational', subtitle: 'Crossfade transition' },
   408→      { zoom: 1.8, title: 'Operational View', subtitle: 'DNA-style task blocks' },
   409→      { zoom: 3.0, title: 'Operational → Execution', subtitle: 'Crossfade transition' },
   410→      { zoom: 4.0, title: 'Execution View', subtitle: 'Detailed task cards' },
   411→    ];
   412→
   413→    const currentZoom = slides[currentSlide].zoom;
   414→
   415→    return (
   416→      <div style={{ width: '100%', height: '100vh', display: 'flex', flexDirection: 'column', background: '#1e293b' }}>
   417→        {/* Title bar */}
   418→        <div
   419→          style={{
   420→            padding: '16px 24px',
   421→            background: 'linear-gradient(to right, #1e40af, #7c3aed)',
   422→            color: 'white',
   423→            display: 'flex',
   424→            justifyContent: 'space-between',
   425→            alignItems: 'center',
   426→          }}
   427→        >
   428→          <div>
   429→            <h2 style={{ margin: 0, fontSize: 24, fontWeight: 600 }}>
   430→              {slides[currentSlide].title}
   431→            </h2>
   432→            <p style={{ margin: '4px 0 0', opacity: 0.8, fontSize: 14 }}>
   433→              {slides[currentSlide].subtitle}
   434→            </p>
   435→          </div>
   436→          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
   437→            <span style={{ fontSize: 14, opacity: 0.8 }}>
   438→              {currentSlide + 1} / {slides.length}
   439→            </span>
   440→            <ButtonGroup>
   441→              <Button
   442→                icon="chevron-left"
   443→                onClick={() => setCurrentSlide(Math.max(0, currentSlide - 1))}
   444→                disabled={currentSlide === 0}
   445→              />
   446→              <Button
   447→                icon="chevron-right"
   448→                onClick={() => setCurrentSlide(Math.min(slides.length - 1, currentSlide + 1))}
   449→                disabled={currentSlide === slides.length - 1}
   450→              />
   451→            </ButtonGroup>
   452→          </div>
   453→        </div>
   454→
   455→        {/* Canvas */}
   456→        <div style={{ flex: 1 }}>
   457→          <FractalCanvasComplete
   458→            width={window.innerWidth}
   459→            height={window.innerHeight - 80}
   460→            initialZoom={currentZoom}
   461→            showConstraintDeck={true}
   462→            showTimeScrubber={true}
   463→            enableKeyboard={false}
   464→            key={currentSlide}
   465→          />
   466→        </div>
   467→      </div>
   468→    );
   469→  },
   470→};
