/**
 * FractalCanvasComplete Stories
 *
 * Demonstrates the complete semantic zoom visualization with all components:
 * - 4 LOD layers with crossfade transitions
 * - Timeline Header with adaptive granularity
 * - Time Scrubber with density visualization
 * - Constraint Deck with resource meters
 */

import type { Meta, StoryObj } from '@storybook/react';
import React, { useState } from 'react';
import { Card, Slider, Tag, Intent, Button, ButtonGroup, Switch, Divider } from '@blueprintjs/core';
import { FractalCanvasComplete } from './FractalCanvasComplete';

// =============================================================================
// META
// =============================================================================

const meta: Meta<typeof FractalCanvasComplete> = {
  title: '03-Demo/FractalCanvasComplete',
  component: FractalCanvasComplete,
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component: `
# FractalCanvas Complete Demo

The complete "Single Pane of Glass" visualization for railway maintenance planning.

## Features

- **4 LOD Levels** with smooth crossfade transitions:
  - **Strategic** (< 0.3x): 12-year heatmap overview
  - **Tactical** (0.3-1.0x): Monthly stacked bars
  - **Operational** (1.0-3.0x): DNA-style task blocks
  - **Execution** (> 3.0x): Detailed task cards

- **Timeline Header**: Adaptive granularity (years → quarters → months → weeks → days)

- **Time Scrubber**: Density visualization with brush selection

- **Constraint Deck**: Resource meters (man-hours, tracks, budget, compliance)

- **Sidebar**: Train list synced with canvas scroll

## Keyboard Shortcuts

- \`1\` - Strategic view
- \`2\` - Tactical view
- \`3\` - Operational view
- \`4\` - Execution view
- \`+\`/\`-\` - Zoom in/out
- \`Home\` - Reset view

## Data

- 128 trains (49 Kinki Sharyo + 79 Alstom)
- 12-year contract period (2024-2036)
- ~60,000 maintenance tasks
        `,
      },
    },
  },
};

export default meta;
type Story = StoryObj<typeof FractalCanvasComplete>;

// =============================================================================
// STORIES
// =============================================================================

export const Default: Story = {
  name: 'Complete Demo',
  render: () => (
    <FractalCanvasComplete
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={0.5}
      showConstraintDeck={true}
      showTimeScrubber={true}
      enableKeyboard={true}
    />
  ),
};

export const Strategic: Story = {
  name: 'Strategic Level',
  render: () => (
    <FractalCanvasComplete
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={0.2}
      showConstraintDeck={true}
      showTimeScrubber={true}
    />
  ),
};

export const Tactical: Story = {
  name: 'Tactical Level',
  render: () => (
    <FractalCanvasComplete
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={0.6}
      showConstraintDeck={true}
      showTimeScrubber={true}
    />
  ),
};

export const Operational: Story = {
  name: 'Operational Level',
  render: () => (
    <FractalCanvasComplete
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={1.8}
      showConstraintDeck={true}
      showTimeScrubber={true}
    />
  ),
};

export const Execution: Story = {
  name: 'Execution Level',
  render: () => (
    <FractalCanvasComplete
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={4.0}
      showConstraintDeck={true}
      showTimeScrubber={true}
    />
  ),
};

export const Minimal: Story = {
  name: 'Minimal (No Panels)',
  render: () => (
    <FractalCanvasComplete
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={0.5}
      showConstraintDeck={false}
      showTimeScrubber={false}
    />
  ),
};

export const Interactive: Story = {
  name: 'Interactive Controls',
  render: () => {
    const [zoom, setZoom] = useState(0.5);
    const [showConstraintDeck, setShowConstraintDeck] = useState(true);
    const [showTimeScrubber, setShowTimeScrubber] = useState(true);

    const getLOD = (z: number) => {
      if (z < 0.3) return 'strategic';
      if (z < 1.0) return 'tactical';
      if (z < 3.0) return 'operational';
      return 'execution';
    };

    const getIntent = (lod: string) => {
      switch (lod) {
        case 'strategic': return Intent.PRIMARY;
        case 'tactical': return Intent.WARNING;
        case 'operational': return Intent.SUCCESS;
        case 'execution': return Intent.DANGER;
        default: return Intent.NONE;
      }
    };

    return (
      <div style={{ width: '100%', height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* Control bar */}
        <Card style={{ borderRadius: 0, padding: 16 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 24, flexWrap: 'wrap' }}>
            <div style={{ flex: 1, minWidth: 300 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                <span style={{ fontWeight: 600 }}>Zoom Level</span>
                <Tag intent={getIntent(getLOD(zoom))} large>
                  {getLOD(zoom).toUpperCase()} ({zoom.toFixed(2)}x)
                </Tag>
              </div>
              <Slider
                min={0.1}
                max={5}
                stepSize={0.01}
                value={zoom}
                onChange={setZoom}
                labelStepSize={1}
              />
            </div>

            <Divider />

            <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
              <Switch
                checked={showTimeScrubber}
                onChange={(e) => setShowTimeScrubber(e.currentTarget.checked)}
                label="Time Scrubber"
              />
              <Switch
                checked={showConstraintDeck}
                onChange={(e) => setShowConstraintDeck(e.currentTarget.checked)}
                label="Constraint Deck"
              />
            </div>

            <Divider />

            <ButtonGroup>
              <Button
                intent={getLOD(zoom) === 'strategic' ? Intent.PRIMARY : Intent.NONE}
                onClick={() => setZoom(0.2)}
              >
                Strategic
              </Button>
              <Button
                intent={getLOD(zoom) === 'tactical' ? Intent.WARNING : Intent.NONE}
                onClick={() => setZoom(0.6)}
              >
                Tactical
              </Button>
              <Button
                intent={getLOD(zoom) === 'operational' ? Intent.SUCCESS : Intent.NONE}
                onClick={() => setZoom(1.8)}
              >
                Operational
              </Button>
              <Button
                intent={getLOD(zoom) === 'execution' ? Intent.DANGER : Intent.NONE}
                onClick={() => setZoom(4.0)}
              >
                Execution
              </Button>
            </ButtonGroup>
          </div>
        </Card>

        {/* Canvas */}
        <div style={{ flex: 1 }}>
          <FractalCanvasComplete
            width={window.innerWidth}
            height={window.innerHeight - 80}
            initialZoom={zoom}
            showConstraintDeck={showConstraintDeck}
            showTimeScrubber={showTimeScrubber}
            enableKeyboard={false}
            key={`${zoom.toFixed(1)}-${showConstraintDeck}-${showTimeScrubber}`}
          />
        </div>
      </div>
    );
  },
};

export const LODTransitionDemo: Story = {
  name: 'LOD Transition Demo',
  render: () => {
    const [autoPlay, setAutoPlay] = useState(false);
    const [zoom, setZoom] = useState(0.1);

    React.useEffect(() => {
      if (!autoPlay) return;

      const interval = setInterval(() => {
        setZoom((z) => {
          const newZoom = z + 0.02;
          if (newZoom > 5) {
            setAutoPlay(false);
            return 0.1;
          }
          return newZoom;
        });
      }, 100);

      return () => clearInterval(interval);
    }, [autoPlay]);

    const getLOD = (z: number) => {
      if (z < 0.3) return 'strategic';
      if (z < 1.0) return 'tactical';
      if (z < 3.0) return 'operational';
      return 'execution';
    };

    const getOpacity = (z: number, level: string) => {
      const TRANSITION = 0.15;
      if (level === 'strategic') {
        if (z <= 0.3 - TRANSITION) return 1;
        if (z >= 0.3) return 0;
        return 1 - (z - (0.3 - TRANSITION)) / TRANSITION;
      }
      if (level === 'tactical') {
        const fadeIn = z < 0.3 + TRANSITION ? (z - 0.3) / TRANSITION : 1;
        const fadeOut = z > 1.0 - TRANSITION ? 1 - (z - (1.0 - TRANSITION)) / TRANSITION : 1;
        return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
      }
      if (level === 'operational') {
        const fadeIn = z < 1.0 + TRANSITION ? (z - 1.0) / TRANSITION : 1;
        const fadeOut = z > 3.0 - TRANSITION ? 1 - (z - (3.0 - TRANSITION)) / TRANSITION : 1;
        return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
      }
      if (level === 'execution') {
        if (z >= 3.0 + TRANSITION) return 1;
        if (z <= 3.0) return 0;
        return (z - 3.0) / TRANSITION;
      }
      return 0;
    };

    const lodColors = {
      strategic: '#3b82f6',
      tactical: '#f59e0b',
      operational: '#22c55e',
      execution: '#ef4444',
    };

    return (
      <div style={{ width: '100%', height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* Control bar */}
        <Card style={{ borderRadius: 0, padding: 16 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
            <ButtonGroup>
              <Button
                icon={autoPlay ? 'pause' : 'play'}
                intent={autoPlay ? Intent.DANGER : Intent.SUCCESS}
                onClick={() => setAutoPlay(!autoPlay)}
              >
                {autoPlay ? 'Pause' : 'Auto-Play'}
              </Button>
              <Button icon="reset" onClick={() => setZoom(0.1)}>
                Reset
              </Button>
            </ButtonGroup>

            <div style={{ flex: 1 }}>
              <Slider
                min={0.1}
                max={5}
                stepSize={0.01}
                value={zoom}
                onChange={setZoom}
                labelStepSize={1}
                disabled={autoPlay}
              />
            </div>

            <div style={{ display: 'flex', gap: 16 }}>
              {(['strategic', 'tactical', 'operational', 'execution'] as const).map((level) => {
                const opacity = getOpacity(zoom, level);
                return (
                  <div key={level} style={{ textAlign: 'center' }}>
                    <div
                      style={{
                        width: 60,
                        height: 8,
                        background: `linear-gradient(to right, ${lodColors[level]} ${opacity * 100}%, #e5e7eb ${opacity * 100}%)`,
                        borderRadius: 4,
                        marginBottom: 4,
                      }}
                    />
                    <div style={{ fontSize: 10, fontWeight: 500 }}>{level}</div>
                    <div style={{ fontSize: 10, color: '#666' }}>{Math.round(opacity * 100)}%</div>
                  </div>
                );
              })}
            </div>
          </div>
        </Card>

        {/* Canvas */}
        <div style={{ flex: 1 }}>
          <FractalCanvasComplete
            width={window.innerWidth}
            height={window.innerHeight - 80}
            initialZoom={zoom}
            showConstraintDeck={true}
            showTimeScrubber={true}
            enableKeyboard={false}
            key={Math.floor(zoom * 10)}
          />
        </div>
      </div>
    );
  },
};

export const Presentation: Story = {
  name: 'Presentation Mode',
  parameters: {
    backgrounds: { default: 'dark' },
  },
  render: () => {
    const [currentSlide, setCurrentSlide] = useState(0);

    const slides = [
      { zoom: 0.15, title: 'Strategic View', subtitle: '12-year capacity heatmap' },
      { zoom: 0.3, title: 'Strategic → Tactical', subtitle: 'Crossfade transition' },
      { zoom: 0.6, title: 'Tactical View', subtitle: 'Monthly workload bars' },
      { zoom: 1.0, title: 'Tactical → Operational', subtitle: 'Crossfade transition' },
      { zoom: 1.8, title: 'Operational View', subtitle: 'DNA-style task blocks' },
      { zoom: 3.0, title: 'Operational → Execution', subtitle: 'Crossfade transition' },
      { zoom: 4.0, title: 'Execution View', subtitle: 'Detailed task cards' },
    ];

    const currentZoom = slides[currentSlide].zoom;

    return (
      <div style={{ width: '100%', height: '100vh', display: 'flex', flexDirection: 'column', background: '#1e293b' }}>
        {/* Title bar */}
        <div
          style={{
            padding: '16px 24px',
            background: 'linear-gradient(to right, #1e40af, #7c3aed)',
            color: 'white',
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
          }}
        >
          <div>
            <h2 style={{ margin: 0, fontSize: 24, fontWeight: 600 }}>
              {slides[currentSlide].title}
            </h2>
            <p style={{ margin: '4px 0 0', opacity: 0.8, fontSize: 14 }}>
              {slides[currentSlide].subtitle}
            </p>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <span style={{ fontSize: 14, opacity: 0.8 }}>
              {currentSlide + 1} / {slides.length}
            </span>
            <ButtonGroup>
              <Button
                icon="chevron-left"
                onClick={() => setCurrentSlide(Math.max(0, currentSlide - 1))}
                disabled={currentSlide === 0}
              />
              <Button
                icon="chevron-right"
                onClick={() => setCurrentSlide(Math.min(slides.length - 1, currentSlide + 1))}
                disabled={currentSlide === slides.length - 1}
              />
            </ButtonGroup>
          </div>
        </div>

        {/* Canvas */}
        <div style={{ flex: 1 }}>
          <FractalCanvasComplete
            width={window.innerWidth}
            height={window.innerHeight - 80}
            initialZoom={currentZoom}
            showConstraintDeck={true}
            showTimeScrubber={true}
            enableKeyboard={false}
            key={currentSlide}
          />
        </div>
      </div>
    );
  },
};

