/**
 * FractalCanvas Stories
 *
 * Demonstrates the complete semantic zoom visualization with all 4 LOD layers
 * and smooth crossfade transitions.
 */

import type { Meta, StoryObj } from '@storybook/react';
import React, { useState } from 'react';
import { Card, Slider, Tag, Intent, Button, ButtonGroup } from '@blueprintjs/core';
import { FractalCanvas } from './FractalCanvas';

// =============================================================================
// META
// =============================================================================

const meta: Meta<typeof FractalCanvas> = {
  title: '03-Demo/FractalCanvas',
  component: FractalCanvas,
  parameters: {
    layout: 'fullscreen',
  },
};

export default meta;
type Story = StoryObj<typeof FractalCanvas>;

// =============================================================================
// STORIES
// =============================================================================

export const Default: Story = {
  name: 'Default View',
  render: () => (
    <FractalCanvas
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={0.5}
    />
  ),
};

export const StrategicZoom: Story = {
  name: 'Strategic Level (< 0.3x)',
  render: () => (
    <FractalCanvas
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={0.2}
    />
  ),
};

export const TacticalZoom: Story = {
  name: 'Tactical Level (0.3-1.0x)',
  render: () => (
    <FractalCanvas
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={0.6}
    />
  ),
};

export const OperationalZoom: Story = {
  name: 'Operational Level (1.0-3.0x)',
  render: () => (
    <FractalCanvas
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={1.8}
    />
  ),
};

export const ExecutionZoom: Story = {
  name: 'Execution Level (> 3.0x)',
  render: () => (
    <FractalCanvas
      width={window.innerWidth}
      height={window.innerHeight}
      initialZoom={3.5}
    />
  ),
};

export const TransitionDemo: Story = {
  name: 'LOD Transition Demo',
  render: () => {
    const [zoom, setZoom] = useState(0.2);

    const getLOD = (z: number) => {
      if (z < 0.3) return 'strategic';
      if (z < 1.0) return 'tactical';
      if (z < 3.0) return 'operational';
      return 'execution';
    };

    const presets = [
      { label: 'Strategic', zoom: 0.15 },
      { label: 'S→T Transition', zoom: 0.3 },
      { label: 'Tactical', zoom: 0.6 },
      { label: 'T→O Transition', zoom: 1.0 },
      { label: 'Operational', zoom: 1.8 },
      { label: 'O→E Transition', zoom: 3.0 },
      { label: 'Execution', zoom: 4.0 },
    ];

    return (
      <div style={{ width: '100%', height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* Control bar */}
        <Card style={{ borderRadius: 0, padding: 16 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
            <div style={{ flex: 1 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                <span style={{ fontWeight: 600 }}>Zoom Level</span>
                <Tag
                  intent={
                    getLOD(zoom) === 'strategic' ? Intent.PRIMARY :
                    getLOD(zoom) === 'tactical' ? Intent.WARNING :
                    getLOD(zoom) === 'operational' ? Intent.SUCCESS :
                    Intent.DANGER
                  }
                  large
                >
                  {getLOD(zoom).toUpperCase()} ({zoom.toFixed(2)}x)
                </Tag>
              </div>
              <Slider
                min={0.1}
                max={5}
                stepSize={0.01}
                value={zoom}
                onChange={setZoom}
                labelStepSize={1}
              />
            </div>
            <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
              {presets.map((p) => (
                <Button
                  key={p.label}
                  small
                  intent={Math.abs(zoom - p.zoom) < 0.05 ? Intent.PRIMARY : Intent.NONE}
                  onClick={() => setZoom(p.zoom)}
                >
                  {p.label}
                </Button>
              ))}
            </div>
          </div>
        </Card>

        {/* Canvas */}
        <div style={{ flex: 1 }}>
          <FractalCanvas
            width={window.innerWidth}
            height={window.innerHeight - 100}
            initialZoom={zoom}
            key={zoom} // Force remount on zoom change
          />
        </div>
      </div>
    );
  },
};

export const ZoomRangeExplorer: Story = {
  name: 'Zoom Range Explorer',
  render: () => {
    const [autoPlay, setAutoPlay] = useState(false);
    const [zoom, setZoom] = useState(0.1);

    // Auto-play effect
    React.useEffect(() => {
      if (!autoPlay) return;

      const interval = setInterval(() => {
        setZoom((z) => {
          const newZoom = z + 0.02;
          if (newZoom > 5) {
            setAutoPlay(false);
            return 0.1;
          }
          return newZoom;
        });
      }, 100);

      return () => clearInterval(interval);
    }, [autoPlay]);

    const getLOD = (z: number) => {
      if (z < 0.3) return 'strategic';
      if (z < 1.0) return 'tactical';
      if (z < 3.0) return 'operational';
      return 'execution';
    };

    const getOpacity = (z: number, level: string) => {
      const TRANSITION = 0.15;
      if (level === 'strategic') {
        if (z <= 0.3 - TRANSITION) return 1;
        if (z >= 0.3) return 0;
        return 1 - (z - (0.3 - TRANSITION)) / TRANSITION;
      }
      if (level === 'tactical') {
        const fadeIn = z < 0.3 + TRANSITION ? (z - 0.3) / TRANSITION : 1;
        const fadeOut = z > 1.0 - TRANSITION ? 1 - (z - (1.0 - TRANSITION)) / TRANSITION : 1;
        return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
      }
      if (level === 'operational') {
        const fadeIn = z < 1.0 + TRANSITION ? (z - 1.0) / TRANSITION : 1;
        const fadeOut = z > 3.0 - TRANSITION ? 1 - (z - (3.0 - TRANSITION)) / TRANSITION : 1;
        return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
      }
      if (level === 'execution') {
        if (z >= 3.0 + TRANSITION) return 1;
        if (z <= 3.0) return 0;
        return (z - 3.0) / TRANSITION;
      }
      return 0;
    };

    return (
      <div style={{ width: '100%', height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* Control bar */}
        <Card style={{ borderRadius: 0, padding: 16 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
            <ButtonGroup>
              <Button
                icon={autoPlay ? 'pause' : 'play'}
                intent={autoPlay ? Intent.DANGER : Intent.SUCCESS}
                onClick={() => setAutoPlay(!autoPlay)}
              >
                {autoPlay ? 'Pause' : 'Auto-Play'}
              </Button>
              <Button icon="reset" onClick={() => setZoom(0.1)}>Reset</Button>
            </ButtonGroup>

            <div style={{ flex: 1 }}>
              <Slider
                min={0.1}
                max={5}
                stepSize={0.01}
                value={zoom}
                onChange={setZoom}
                labelStepSize={1}
                disabled={autoPlay}
              />
            </div>

            <div style={{ display: 'flex', gap: 16 }}>
              {['strategic', 'tactical', 'operational', 'execution'].map((level) => {
                const opacity = getOpacity(zoom, level);
                return (
                  <div key={level} style={{ textAlign: 'center' }}>
                    <div
                      style={{
                        width: 60,
                        height: 8,
                        background: `linear-gradient(to right, ${
                          level === 'strategic' ? '#3b82f6' :
                          level === 'tactical' ? '#f59e0b' :
                          level === 'operational' ? '#22c55e' :
                          '#ef4444'
                        } ${opacity * 100}%, #e5e7eb ${opacity * 100}%)`,
                        borderRadius: 4,
                        marginBottom: 4,
                      }}
                    />
                    <div style={{ fontSize: 10 }}>{level}</div>
                    <div style={{ fontSize: 10, color: '#666' }}>{Math.round(opacity * 100)}%</div>
                  </div>
                );
              })}
            </div>
          </div>
        </Card>

        {/* Canvas */}
        <div style={{ flex: 1 }}>
          <FractalCanvas
            width={window.innerWidth}
            height={window.innerHeight - 100}
            initialZoom={zoom}
            key={Math.floor(zoom * 10)} // Only remount on significant changes
          />
        </div>
      </div>
    );
  },
};

