     1→/**
     2→ * POC: Semantic Zoom with Crossfade Transitions
     3→ *
     4→ * Demonstrates smooth LOD transitions using opacity crossfade:
     5→ * - Strategic (zoom < 0.3): Heatmap overview
     6→ * - Tactical (0.3 <= zoom < 1.0): Stacked bars
     7→ * - Operational (1.0 <= zoom < 3.0): DNA Gantt pattern
     8→ * - Execution (zoom >= 3.0): Detailed task cards
     9→ *
    10→ * Key concepts:
    11→ * 1. Each LOD layer renders independently
    12→ * 2. Crossfade opacity based on zoom proximity to threshold
    13→ * 3. Smooth 60fps transitions without jarring changes
    14→ */
    15→
    16→import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
    17→import type { Meta, StoryObj } from '@storybook/react';
    18→import { useGesture } from '@use-gesture/react';
    19→import { Card, Tag, Intent, Divider, ProgressBar, Slider } from '@blueprintjs/core';
    20→
    21→import { COLORS, LOD_THRESHOLDS, ANIMATION, getLODLevel } from '../../data/mock-config';
    22→import type { LODLevel } from '../../data/mock-config';
    23→
    24→// =============================================================================
    25→// TYPES
    26→// =============================================================================
    27→
    28→interface ViewportState {
    29→  zoom: number;
    30→  x: number;
    31→  y: number;
    32→}
    33→
    34→interface LayerOpacities {
    35→  strategic: number;
    36→  tactical: number;
    37→  operational: number;
    38→  execution: number;
    39→}
    40→
    41→// =============================================================================
    42→// CONSTANTS
    43→// =============================================================================
    44→
    45→const CROSSFADE_RANGE = 0.15; // Opacity transition range around threshold
    46→
    47→const LOD_COLORS: Record<LODLevel, string> = {
    48→  strategic: '#3b82f6',    // blue-500
    49→  tactical: '#8b5cf6',     // violet-500
    50→  operational: '#f59e0b',  // amber-500
    51→  execution: '#10b981',    // emerald-500
    52→};
    53→
    54→const LOD_DESCRIPTIONS: Record<LODLevel, string> = {
    55→  strategic: '12-Year Heatmap Overview',
    56→  tactical: 'Quarterly Stacked Bars',
    57→  operational: 'Monthly DNA Gantt',
    58→  execution: 'Weekly Task Details',
    59→};
    60→
    61→// =============================================================================
    62→// OPACITY CALCULATION
    63→// =============================================================================
    64→
    65→/**
    66→ * Calculate layer opacities based on current zoom level.
    67→ * Uses smooth crossfade transitions near thresholds.
    68→ */
    69→function calculateLayerOpacities(zoom: number): LayerOpacities {
    70→  const { strategic, tactical, operational } = LOD_THRESHOLDS;
    71→
    72→  // Helper: smooth step function for crossfade
    73→  const smoothStep = (value: number, edge0: number, edge1: number): number => {
    74→    const t = Math.max(0, Math.min(1, (value - edge0) / (edge1 - edge0)));
    75→    return t * t * (3 - 2 * t); // Smooth Hermite interpolation
    76→  };
    77→
    78→  // Calculate fade factors for each threshold
    79→  const fadeStrategicToTactical = smoothStep(
    80→    zoom,
    81→    strategic - CROSSFADE_RANGE,
    82→    strategic + CROSSFADE_RANGE
    83→  );
    84→
    85→  const fadeTacticalToOperational = smoothStep(
    86→    zoom,
    87→    tactical - CROSSFADE_RANGE,
    88→    tactical + CROSSFADE_RANGE
    89→  );
    90→
    91→  const fadeOperationalToExecution = smoothStep(
    92→    zoom,
    93→    operational - CROSSFADE_RANGE,
    94→    operational + CROSSFADE_RANGE
    95→  );
    96→
    97→  // Calculate final opacities
    98→  return {
    99→    strategic: 1 - fadeStrategicToTactical,
   100→    tactical: fadeStrategicToTactical * (1 - fadeTacticalToOperational),
   101→    operational: fadeTacticalToOperational * (1 - fadeOperationalToExecution),
   102→    execution: fadeOperationalToExecution,
   103→  };
   104→}
   105→
   106→// =============================================================================
   107→// MOCK LOD LAYER COMPONENTS
