   466→
   467→// =============================================================================
   468→// MAIN COMPONENT
   469→// =============================================================================
   470→
   471→function SemanticZoomDemo() {
   472→  const containerRef = useRef<HTMLDivElement>(null);
   473→
   474→  // Viewport state
   475→  const [viewport, setViewport] = useState<ViewportState>({
   476→    zoom: 0.15,
