   480→
   481→  // Calculate current LOD and layer opacities
   482→  const currentLOD = useMemo(() => getLODLevel(viewport.zoom), [viewport.zoom]);
   483→  const opacities = useMemo(() => calculateLayerOpacities(viewport.zoom), [viewport.zoom]);
   484→
   485→  // Zoom change handler
   486→  const handleZoomChange = useCallback((newZoom: number) => {
   487→    setViewport((prev) => ({ ...prev, zoom: newZoom }));
   488→  }, []);
   489→
   490→  // Gesture bindings for wheel zoom
   491→  const bind = useGesture({
   492→    onWheel: ({ delta: [, dy], event }) => {
   493→      event.preventDefault();
   494→      setViewport((prev) => ({
   495→        ...prev,
   496→        zoom: Math.max(0.1, Math.min(5, prev.zoom * (1 - dy * 0.002))),
   497→      }));
   498→    },
   499→  }, {
   500→    wheel: { preventDefault: true },
   501→  });
   502→
   503→  return (
   504→    <div
   505→      ref={containerRef}
   506→      {...bind()}
   507→      style={{
   508→        width: '100%',
   509→        height: '100vh',
   510→        position: 'relative',
   511→        background: COLORS.bg.primary,
   512→        overflow: 'hidden',
   513→        touchAction: 'none',
   514→      }}
   515→    >
   516→      {/* LOD Layers with crossfade */}
   517→      <StrategicLayer opacity={opacities.strategic} zoom={viewport.zoom} />
   518→      <TacticalLayer opacity={opacities.tactical} zoom={viewport.zoom} />
   519→      <OperationalLayer opacity={opacities.operational} zoom={viewport.zoom} />
   520→      <ExecutionLayer opacity={opacities.execution} zoom={viewport.zoom} />
   521→
   522→      {/* UI Overlays */}
   523→      <InfoPanel viewport={viewport} opacities={opacities} currentLOD={currentLOD} />
   524→      <ZoomControl zoom={viewport.zoom} onZoomChange={handleZoomChange} />
   525→    </div>
   526→  );
   527→}
   528→
   529→// =============================================================================
   530→// STORYBOOK CONFIG
   531→// =============================================================================
