 * Shows workload distribution by maintenance type across trains.
 */

import type { Meta, StoryObj } from '@storybook/react';
import React, { useState } from 'react';
import { Card, Slider, Tag, Intent } from '@blueprintjs/core';
import { TacticalLayer } from './TacticalLayer';
import { generateMockData } from '../../data/mock-generator';
import type { AggregatedCell } from '../../data/mock-generator';

// =============================================================================
// META
// =============================================================================

const meta: Meta<typeof TacticalLayer> = {
  title: '02-Layers/Tactical',
