  parameters: {
    layout: 'fullscreen',
  },
};

export default meta;
type Story = StoryObj<typeof TacticalLayer>;

// =============================================================================
// MOCK DATA
// =============================================================================

const mockData = generateMockData();

// =============================================================================
// STORIES
// =============================================================================

export const Default: Story = {
  name: 'Default View',
  render: () => {
    const [hoveredCell, setHoveredCell] = useState<AggregatedCell | null>(null);
    const [selectedCell, setSelectedCell] = useState<AggregatedCell | null>(null);

    return (
      <div style={{ width: '100%', height: '100vh', background: '#f4f4f5' }}>
        <TacticalLayer
          cells={mockData.aggregatedByMonth}
          trains={mockData.trains}
          width={window.innerWidth}
          height={window.innerHeight}
          hoveredCell={hoveredCell}
          onCellHover={setHoveredCell}
          onCellClick={setSelectedCell}
        />

        {/* Selected cell detail */}
        {selectedCell && (
          <div
            style={{
              position: 'absolute',
              bottom: 16,
              left: 16,
              background: 'white',
              padding: 16,
              borderRadius: 8,
              boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
              maxWidth: 280,
            }}
          >
            <div style={{ fontWeight: 600, marginBottom: 8 }}>
              Selected: {mockData.trains[selectedCell.trainIndex]?.name}
            </div>
            <div style={{ fontSize: 12, color: '#666', marginBottom: 12 }}>
              {['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'][selectedCell.periodIndex % 12]} {2024 + Math.floor(selectedCell.periodIndex / 12)}
            </div>
            <div style={{ fontSize: 12 }}>
              <div>Tasks: {selectedCell.totalTasks}</div>
              <div>Man-Hours: {selectedCell.totalManHours.toLocaleString()}</div>
              <div>Cost: {(selectedCell.totalCostAed / 1000).toFixed(0)}K AED</div>
              <div>Utilization: {selectedCell.utilizationPercent.toFixed(0)}%</div>
            </div>
            <button
              onClick={() => setSelectedCell(null)}
              style={{
                marginTop: 12,
                padding: '4px 12px',
                cursor: 'pointer',
              }}
            >
              Close
            </button>
          </div>
        )}
      </div>
    );
  },
};

