/**
 * Operational Layer Stories
 *
 * Demonstrates the DNA-style Gantt view for operational planning.
 * Shows individual tasks as colored blocks on train rows.
 */

import type { Meta, StoryObj } from '@storybook/react';
import React, { useState, useMemo } from 'react';
import { Card, Slider, Tag, Intent, Button, ButtonGroup } from '@blueprintjs/core';
import { OperationalLayer } from './OperationalLayer';
import { generateMockData, getTasksInRange } from '../../data/mock-generator';
import type { Task } from '../../data/mock-generator';

// =============================================================================
// META
// =============================================================================

const meta: Meta<typeof OperationalLayer> = {
  title: '02-Layers/Operational',
  component: OperationalLayer,
  parameters: {
    layout: 'fullscreen',
  },
};

export default meta;
type Story = StoryObj<typeof OperationalLayer>;

// =============================================================================
// MOCK DATA
// =============================================================================

const mockData = generateMockData();

// Get tasks for a specific time range (2030 Q2 for demo)
const demoTasks = getTasksInRange(
  mockData,
  new Date('2030-01-01'),
  new Date('2030-12-31')
);

// =============================================================================
// STORIES
// =============================================================================

export const Default: Story = {
  name: 'Default View',
  render: () => {
    const [hoveredTask, setHoveredTask] = useState<Task | null>(null);
    const [selectedTask, setSelectedTask] = useState<Task | null>(null);

    return (
      <div style={{ width: '100%', height: '100vh', background: '#f8fafc' }}>
        <OperationalLayer
          tasks={demoTasks}
          trains={mockData.trains}
          width={window.innerWidth}
          height={window.innerHeight}
          hoveredTaskId={hoveredTask?.id}
          selectedTaskId={selectedTask?.id}
          onTaskHover={setHoveredTask}
          onTaskClick={setSelectedTask}
          cameraX={2300} // Start near mid-2030
          zoom={1.5}
        />

        {/* Hover tooltip */}
        {hoveredTask && !selectedTask && (
          <div
            style={{
              position: 'absolute',
              top: 16,
              left: 16,
              background: 'white',
              padding: 12,
              borderRadius: 8,
              boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
              fontSize: 12,
              minWidth: 200,
            }}
          >
            <div style={{ fontWeight: 600, marginBottom: 4 }}>{hoveredTask.name}</div>
            <div style={{ color: '#666', fontSize: 11, marginBottom: 8 }}>
              {hoveredTask.trainId}
            </div>
            <div>Status: <Tag minimal intent={
              hoveredTask.status === 'completed' ? Intent.SUCCESS :
              hoveredTask.status === 'in-progress' ? Intent.PRIMARY :
              hoveredTask.status === 'overdue' ? Intent.DANGER :
              Intent.NONE
            }>{hoveredTask.status}</Tag></div>
            <div style={{ marginTop: 4 }}>Duration: {hoveredTask.durationHours}h</div>
            <div>Man-Hours: {hoveredTask.manHours}</div>
            {hoveredTask.hasConflict && (
              <div style={{ color: '#ef4444', marginTop: 4, fontWeight: 500 }}>
                ⚠️ Has Conflict
              </div>
            )}
          </div>

/**
 * Execution Layer Stories
 *
 * Demonstrates the most detailed view for daily operational planning.
 * Shows individual task cards with full information, resources, and status.
 */

import type { Meta, StoryObj } from '@storybook/react';
import React, { useState, useMemo } from 'react';
import { Card, Slider, Tag, Intent, Button, ButtonGroup, Divider } from '@blueprintjs/core';
import { ExecutionLayer } from './ExecutionLayer';
import { generateMockData, getTasksInRange } from '../../data/mock-generator';
import type { Task } from '../../data/mock-generator';

// =============================================================================
// META
// =============================================================================

const meta: Meta<typeof ExecutionLayer> = {
  title: '02-Layers/Execution',
  component: ExecutionLayer,
  parameters: {
    layout: 'fullscreen',
  },
};

export default meta;
type Story = StoryObj<typeof ExecutionLayer>;

// =============================================================================
// MOCK DATA
// =============================================================================

const mockData = generateMockData();

// Get tasks for a specific week (for demo - showing June 2030)
const demoTasks = getTasksInRange(
  mockData,
  new Date('2030-06-01'),
  new Date('2030-06-30')
);

// =============================================================================
// STORIES
// =============================================================================

export const Default: Story = {
  name: 'Default View',
  render: () => {
    const [selectedTask, setSelectedTask] = useState<Task | null>(null);
    const [hoveredTask, setHoveredTask] = useState<Task | null>(null);

    return (
      <div style={{ width: '100%', height: '100vh', background: '#f8fafc' }}>
        <ExecutionLayer
          tasks={demoTasks}
          trains={mockData.trains}
          width={window.innerWidth}
          height={window.innerHeight}
          selectedTaskId={selectedTask?.id}
          onTaskClick={setSelectedTask}
          onTaskHover={setHoveredTask}
          cameraX={2345} // Start at June 2030
          zoom={3.5}
        />

        {/* Selected task detail panel */}
        {selectedTask && (
          <Card
            style={{
              position: 'absolute',
              top: 60,
              right: 16,
              width: 320,
              padding: 16,
            }}
            elevation={3}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 14 }}>{selectedTask.name}</div>
                <div style={{ color: '#666', fontSize: 11, marginTop: 2 }}>{selectedTask.id}</div>
              </div>
              <Button minimal icon="cross" onClick={() => setSelectedTask(null)} />
            </div>

            <Divider style={{ margin: '12px 0' }} />

            <div style={{ fontSize: 12 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
                <span style={{ color: '#666' }}>Train:</span>
                <span style={{ fontWeight: 500 }}>{selectedTask.trainId}</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
                <span style={{ color: '#666' }}>Start:</span>
                <span style={{ fontWeight: 500 }}>
                  {selectedTask.startDate.toLocaleDateString()} {selectedTask.startDate.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>

